import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

export function createServer() {
  const server = new McpServer({ name: "calc-server", version: "1.0.0" });

  // --- Local registries so we can expose listTools / listResources -------
  const _toolList: Array<{
    name: string;
    title?: string;
    description?: string;
    inputSchema: Record<string, unknown>;
  }> = [];
  const _resourceList: Array<{
    uri: string;
    name: string;
  }> = [];

  // Helper: convert a ZodRawShape compat into MCP-compatible JSON Schema
  function zodShapeToJsonSchema(shape: z.ZodRawShapeCompat): Record<string, unknown> {
    const properties: Record<string, unknown> = {};
    const required: string[] = [];
    for (const [key, schema] of Object.entries(shape)) {
      const zodType = (schema as z.ZodTypeAny)._def.typeName;
      let jsonType: string | undefined;
      if (zodType === "ZodNumber") jsonType = "number";
      else if (zodType === "ZodString") jsonType = "string";
      else if (zodType === "ZodBoolean") jsonType = "boolean";
      else if (zodType === "ZodOptional") {
        const inner = (schema as z.ZodOptional<z.ZodTypeAny>).innerType;
        const innerTypeName = (inner as z.ZodTypeAny)._def.typeName;
        jsonType =
          innerTypeName === "ZodNumber" ? "number"
            : innerTypeName === "ZodString" ? "string"
              : innerTypeName === "ZodBoolean" ? "boolean"
                : undefined;
      }
      if (jsonType) {
        properties[key] = { type: jsonType };
      } else {
        properties[key] = {};
      }
      required.push(key);
    }
    return { type: "object", properties, required };
  }

  // Register the "calculate_sum" tool.
  // SDK v1.x McpServer.tool() signature: tool(name, description?, paramsSchema, cb)
  const calcTool = server.tool(
    "calculate_sum",
    "Adds two numbers together",
    { a: z.number(), b: z.number() },
    async ({ a, b }) => ({
      content: [{ type: "text", text: String(a + b) }],
    })
  );
  _toolList.push({
    name: "calculate_sum",
    title: calcTool.title ?? undefined,
    description: calcTool.description ?? undefined,
    inputSchema: zodShapeToJsonSchema({ a: z.number(), b: z.number() }),
  });

  // Register the "config" static resource.
  // SDK v1.x McpServer.resource() signature: resource(name, uri, readCallback)
  // ReadResourceCallback returns { contents: [{ uri, text }] }
  server.resource(
    "config",
    "config://app/settings",
    async (_uri) => ({
      contents: [
        {
          uri: _uri.toString(),
          text: JSON.stringify({ theme: "dark", debug: false }),
        },
      ],
    })
  );
  _resourceList.push({ uri: "config://app/settings", name: "config" });

  // Expose listing methods expected by the test suite.
  server.listTools = async () => ({ tools: _toolList });
  server.listResources = async () => ({ resources: _resourceList });

  return server;
}

if (process.env.NODE_ENV !== 'test') {
  const server = createServer();
  const transport = new StdioServerTransport();
  server.connect(transport).then(() => {
    console.error("Calculation MCP Server running on stdio");
  }).catch(console.error);
}

