import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

// ---------------------------------------------------------------------------
// Simple Zod → MCP JSON Schema converter (only covers what this demo needs)
// ---------------------------------------------------------------------------
interface RawShapeEntry {
  _def: { typeName: string };
}

function zodSchemaToMcpJsonType(schema: unknown): string | undefined {
  const typeName = (schema as RawShapeEntry)._def?.typeName;
  switch (typeName) {
    case "ZodNumber": return "number";
    case "ZodString": return "string";
    case "ZodBoolean": return "boolean";
    case "ZodOptional": {
      // unwrap the inner non-optional schema
      const unwrapped = (schema as { _def: { innerType?: unknown } })._def.innerType;
      return zodSchemaToMcpJsonType(unwrapped);
    }
    default: return undefined;
  }
}

function buildJsonSchema(shape: Record<string, unknown>): Record<string, unknown> {
  const properties: Record<string, unknown> = {};
  const required: string[] = [];
  for (const [key, value] of Object.entries(shape)) {
    const jsonType = zodSchemaToMcpJsonType(value);
    if (jsonType !== undefined) {
      properties[key] = { type: jsonType };
    } else {
      properties[key] = {};
    }
    required.push(key);
  }
  return { type: "object", properties, required };
}

// ---------------------------------------------------------------------------
// Server factory
// ---------------------------------------------------------------------------
export function createServer() {
  const server = new McpServer({ name: "calc-server", version: "1.0.0" });

  // --- Local registries so we can expose listTools / listResources -------
  const toolList: Array<{
    name: string;
    title?: string;
    description?: string;
    inputSchema: Record<string, unknown>;
  }> = [];
  const resourceList: Array<{
    uri: string;
    name: string;
  }> = [];

  // Register the "calculate_sum" action tool.
  // SDK v1.x McpServer.tool() signature: tool(name, description?, paramsSchema, cb)
  const calcTool = server.tool(
    "calculate_sum",
    "Adds two numbers together",
    { a: z.number(), b: z.number() },
    async ({ a, b }) => ({
      content: [{ type: "text", text: String(a + b) }],
    })
  );
  toolList.push({
    name: "calculate_sum",
    title: calcTool.title ?? undefined,
    description: calcTool.description ?? undefined,
    inputSchema: buildJsonSchema({ a: z.number(), b: z.number() }),
  });

  // Register the "config" read-only resource.
  // SDK v1.x McpServer.resource() signature: resource(name, uri, readCallback)
  // ReadResourceCallback returns { contents: [{ uri, text }] }
  server.resource(
    "config",
    "config://app/settings",
    async (_uri) => ({
      contents: [
        {
          uri: _uri.toString(),
          text: JSON.stringify({ theme: "dark", debug: false }),
        },
      ],
    })
  );
  resourceList.push({ uri: "config://app/settings", name: "config" });

  // Expose listing methods expected by the test suite.
  (server as unknown as typeof server & {
    listTools(): Promise<{ tools: typeof toolList }>;
    listResources(): Promise<{ resources: typeof resourceList }>;
  }).listTools = async () => ({ tools: toolList });
  (server as unknown as typeof server & {
    listTools(): Promise<{ tools: typeof toolList }>;
    listResources(): Promise<{ resources: typeof resourceList }>;
  }).listResources = async () => ({ resources: resourceList });

  return server as any;
}

if (process.env.NODE_ENV !== 'test') {
  const server = createServer();
  const transport = new StdioServerTransport();
  server.connect(transport).then(() => {
    console.error("Calculation MCP Server running on stdio");
  }).catch(console.error);
}

